digraph G {
rankdir=LR;

node[shape=circle];

subgraph cluster_CPU {
label="Central Processing Unit (CPU)";
style=filled;
color=lightblue;

node[shape=circle, style=filled]
   CU;
label=C\_Unit;
ljust=r;

draw CU;

node[shape=circle, style=filled]
   PC;
label=P\_COUNTER;
ljust=r;

draw PC;

node[shape=circle, style=filled]
   IR;
label=I\_REGISTER;
ljust=r;

draw IR;

subgraph cluster_ALU {
label="Arithmetic Logic Unit (ALU)";
style=filled;
color=lightgreen;

node[shape=circle, style=filled]
   ALU;
label=A\_LUnit;
ljust=r;

draw ALU;

subgraph cluster_Memory {
label="Main Memory (M)";
style=filled;
color=lightyellow;

draw M;
}

node[shape=circle, style=filled]
   MAR;
label=M\_ADDRESS;
ljust=r;

draw MAR;

node[shape=circle, style=filled]
   MBR;
label=M\_BUFFER;
ljust=r;

draw MBR;

edge[style=dashed]
CU->PC[label=fetch];
PC->MAR[label=fetch];
MAR->M[label=read);
IR->CU[label=decode];
MBR->ALU[label=data];
MAR->ALU[label=data];
ALU->PC[label=result];
MBR->IR[label=result];
IR->CU[label=result];
}

subgraph cluster_IO {
label="Input/Output (I/O) Equipment";
style=filled;
color=lightred;
draw I;
}

edge[style=dashed]
CU->MAR[label=write);
MBR->I[label=data];
}
